import{_ as e,o as a,c as t,j as r,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"特殊子弹系列","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/特殊子弹系列.md","filePath":"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/特殊子弹系列.md"}'),n={name:"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/特殊子弹系列.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"特殊子弹系列",tabindex:"-1"},[p("特殊子弹系列 "),r("a",{class:"header-anchor",href:"#特殊子弹系列","aria-label":'Permalink to "特殊子弹系列"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),s('<h1 id="特殊子弹系列-1" tabindex="-1">特殊子弹系列 <a class="header-anchor" href="#特殊子弹系列-1" aria-label="Permalink to &quot;特殊子弹系列&quot;">​</a></h1><p>特殊子弹系列（主神版）<br> 描述：好的枪械往往被人们所看中，但一颗好的子弹同样有着与枪械本身相差无异的重要性。</p><p>若无特殊说明，则只有无限子弹的枪械（且只能）使用无限版本特殊子弹，无法单发填装，选择的无限版本特殊子弹会永久性替换掉原本的子弹类型。</p><p>特殊子弹通常会具有专属的减值，这意味着你在使用这些子弹进行攻击时，在攻击上承受等量的器械减值（理所当然的，一次攻击只能使用一种特殊子弹，你并不能将多种子弹叠加在一次攻击里生效）。<br> ——————————————————</p><p>飞镖弹<br> 价格：500分/3发<br> 减值：1<br> 描述：飞镖弹不能直接杀伤目标，但内藏小箭会在惯性下脱离弹头，进入人体后发生剧烈翻滚，将目标的骨骼与肌肉组织绞烂打碎。<br> 效果：你需要正常进行换弹来填装这颗子弹，使枪械武器的下一次攻击时获得【高速1】【破甲1】【额外造成1点韧性伤害】的效果。</p><p>银弹<br> 价格：500分/3发<br> 减值：2<br> 描述：通过特殊的工艺，将圣水封进银合金当中制造的子弹，对于黑暗生物可以造成更大的杀伤性。<br> 效果：你需要正常进行换弹来填装这颗子弹，使枪械武器的下一次攻击时获得【法破】与针对黑暗生物的【1个额外附加成功数】。</p><p>医疗弹<br> 价格：500分/3发<br> 减值：2<br> 吗啡、粘合剂、抗生素等药物混合，按比例封装在子弹当中，可以使被命中部位的伤口快速止血，闭合。由于其配备设备降低了初速度，不会对于伤口造成二次伤害。<br> 效果：你需要正常进行换弹来填装这颗子弹，使枪械武器的下一次攻击追加一颗医疗弹，这颗医疗弹可以选择射程内的任一友方目标获得快速医疗1（医疗点数12），持续三轮。<br> 同时只能有一个目标享受医疗弹提供的快速医疗。<br> 【医疗弹比较特殊，由于是进行一次射击后的追加其他影响，可以和其他子弹在一起攻击中生效。】</p><p>“狂笑”神经毒素弹<br> 价格：1000分/20发<br> 减值：0<br> 描述：[Why so serious ?]<br> 该种子弹来自哥谭，由大名鼎鼎的J先生用其独特的神经毒素制作而成，一旦被该子弹射中，受伤者的脸部将不可避免的做出狂笑的表情。<br> 与此同时，子弹中的独特信息素将会完完全全的暴露你的位置。既然如此，那就，带着你的笑容，然后逃亡吧......<br> 效果：<br> 外形是银色的子弹，上面画着一个狰狞的红色笑脸。在击中敌人时，狂笑会将所有的伤害出目转化为亢奋点数，以标准强韧形式豁免。同时，使用者对于受击者进行一次侦查对抗，并视为拥有D级侦测等级，若对抗成功，则对方的位置会完全暴露给你，这个侦测等级将持续一个场景。<br> 选开：ST也可以将信息素改为被击中者不可遏制的狂笑<br> 与此同时，该神经毒素的喷雾版也采取相同的定价，1000/瓶（可喷20次），固定强韧豁免DC5。</p><p>“忘川”反模因弹药<br> 价格：D+500/10发<br> 减值：0<br> 描述：在某个被“妖魔”侵扰的世界，各个国度使用着不同的手段地域妖魔，在这其中，最为诡谲的则是东方大国“九夏”的反模因技术，通过移除认知的方式，抹除依靠信息和观测存在的“妖魔”<br> 精致的弹壳上，刻着密密麻麻的无法被认知的铭文，强行凝神去看，只能得到大脑中的一片眩晕<br> 效果：为不影响射击者，弹药携带的反模因量有限，所以“忘川”反模因弹药必须至少造成1点伤害才会生效，当弹头进入目标的体内后，反模因才开始发作，从中弹当轮开始计算，持续1轮。<br> 在反模因的影响下，被攻击者将会短暂失去对自身一部分对自身行为的认知，失去对移动这一概念的认知，停留原地不能移动，但不因此失去闪避和基础防御，也不会因为失速而坠落，这是D级信息来源的【类定身】效果，可被免疫定身的效果正常免疫。</p><p>贫铀穿甲弹<br> 价格：D+500分/9发<br> 减值：1<br> 描述：由铀238硬质合金打造而成的穿甲弹，其不仅具有放射性还具有化学毒性，弹头表面发热自燃后，形成6000°以上的高温熔毁目标护甲，随后在目标体内爆炸形成杀伤。<br> 效果：你需要正常进行换弹来填装这颗子弹，使枪械武器的下一次攻击时获得【贯穿】【熔毁5】【额外造成2点韧性伤害】。</p><p>龙息弹<br> 价格：D+500分/9发<br> 减值：1<br> 描述：填装大量金属镁的弹药，在发射后会迅速自燃对目标喷射出火龙般的长线，点燃目标的同时极难扑灭。<br> 效果：你需要正常进行换弹来填装这颗子弹，使枪械武器的下一次攻击时改为对于武器射程直线的所有目标生效，同时附带1点不可豁免的燃烧不良点数（可叠加），额外造成1点严重伤害，伤害类型转变为火焰能量伤害。</p><p>贵金弹<br> 价格：D+500分/9发<br> 减值：1<br> 描述：在贵重黄金制成的弹壳中封入巨大魔力的特殊子弹，其威力非常强大。虽然黄金的质地不适合作为子弹，但作为高效传递魔力的材质可以在表面雕刻术式来定型。<br> 效果：你需要正常进行换弹来填装这颗子弹，使枪械武器的下一次攻击时附带【5点额外严重伤害】与【法破】。</p><p>逻辑工作室-高速粉碎弹<br> 价格：D+500/1发<br> 减值：0<br> 描述：来自一座名为“都市”的建立在前文明废墟之上的国度中的一个名为逻辑工作室的高端工坊所制作的子弹，十分昂贵，作为一次性消费品放在主神空间中，这个价格同样的昂贵。<br> 正如他的名字一般，高速与粉碎是他的名字也是他的作用威力与效果，极快的速度与粉碎敌人任何防御的威力。<br> 效果：你需要正常进行换弹来填装这颗子弹，使枪械武器的下一次攻击时获得【超级贯穿】【接触攻击】【先制B】，并获得5DP的器械加值与1个额外附加成功数。</p><p>———————<br> 飞镖弹的无限子弹版本价格为D+500分，获得的额外高速/破甲皆提升至【3】。<br> ——<br> 银弹的的无限子弹版本价格为D+500，额外获得【破魔5】。<br> ——<br> 医疗弹的无限子弹版本价格为D+500，提供的快速医疗提升至2（医疗点数32），持续一场景，其他方面不变。<br> ——<br> 贫铀穿甲弹的无限子弹版本价格为C+1000。<br> ——<br> 龙息弹的无限子弹版本价格为C+1000。<br> ——<br> 贵金弹的无限子弹版本价格为C+1000。<br> ——<br> “狂笑”神经毒素弹，“忘川”反模因弹药，逻辑工作室-高速粉碎弹，不存在无限子弹的版本。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const f=e(n,[["render",o]]);export{D as __pageData,f as default};
